import React, { useEffect, useState } from "react";
import axios from "axios";

const CustomerDashboard = () => {
  const [jobs, setJobs] = useState([]);

  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    price: ""
  });

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    fetchMyJobs();
  }, []);

  // GET MY POSTED JOBS (WITH TOKEN)
  const fetchMyJobs = async () => {
    try {
      const token = localStorage.getItem("token");

      const res = await axios.get(
        `http://localhost:5000/api/jobs/posted/${user.email}`,
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      setJobs(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // HANDLE INPUT CHANGE
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // POST JOB (IMPORTANT FEATURE)
  const postJob = async (e) => {
    e.preventDefault();

    try {
      const token = localStorage.getItem("token");

      await axios.post(
        "http://localhost:5000/api/jobs/create",
        {
          ...form,
          postedBy: user.email
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      alert("Job Posted Successfully");

      setForm({
        title: "",
        description: "",
        location: "",
        price: ""
      });

      fetchMyJobs();
    } catch (err) {
      console.log(err);
    }
  };

  // LOGOUT
  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    window.location.href = "/login";
  };

  return (
    <div style={styles.page}>

      <div style={styles.topbar}>
        <h2>Customer Dashboard</h2>

        <button onClick={logout} style={styles.logout}>
          Logout
        </button>
      </div>

      {/* POST JOB FORM */}
      <div style={styles.card}>
        <h3>Post a Job</h3>

        <form onSubmit={postJob} style={styles.form}>

          <input
            name="title"
            placeholder="Job Title"
            value={form.title}
            onChange={handleChange}
            style={styles.input}
          />

          <input
            name="description"
            placeholder="Description"
            value={form.description}
            onChange={handleChange}
            style={styles.input}
          />

          <input
            name="location"
            placeholder="Location"
            value={form.location}
            onChange={handleChange}
            style={styles.input}
          />

          <input
            name="price"
            placeholder="Price"
            value={form.price}
            onChange={handleChange}
            style={styles.input}
          />

          <button type="submit" style={styles.btn}>
            Post Job
          </button>

        </form>
      </div>

      {/* MY JOBS */}
      <h3>My Posted Jobs</h3>

      {jobs.length === 0 && <p>No jobs posted yet</p>}

      {jobs.map((job) => (
        <div key={job._id} style={styles.card}>
          <h4>{job.title}</h4>
          <p>{job.description}</p>
          <p>{job.location}</p>
          <p>{job.price}</p>
          <p>Status: {job.status}</p>
        </div>
      ))}

    </div>
  );
};

export default CustomerDashboard;

/* ---------------- STYLES ---------------- */

const styles = {
  page: {
    padding: "20px",
    fontFamily: "Segoe UI",
    background: "#f5f6f8",
    minHeight: "100vh"
  },

  topbar: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: "20px"
  },

  card: {
    background: "white",
    padding: "15px",
    borderRadius: "10px",
    marginBottom: "15px",
    border: "1px solid #e5e7eb"
  },

  form: {
    display: "flex",
    flexDirection: "column"
  },

  input: {
    padding: "10px",
    margin: "5px 0",
    border: "1px solid #ddd",
    borderRadius: "6px"
  },

  btn: {
    background: "#16a34a",
    color: "white",
    border: "none",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "6px",
    cursor: "pointer"
  },

  logout: {
    background: "red",
    color: "white",
    border: "none",
    padding: "8px 12px",
    borderRadius: "6px",
    cursor: "pointer"
  }
};
